module.exports=[70874,a=>{"use strict";let b=[{slug:"what-is-usdt",level:"beginner",category:"basics",icon:"💵",readTime:6,title:{ar:"ما هو USDT وكيف يعمل؟",en:"What is USDT and how does it work?"},excerpt:{ar:"دليل شامل لفهم عملة تِثر (USDT)، الفرق بينها وبين الدولار، وآلية ربطها بالدولار الأمريكي.",en:"A comprehensive guide to understanding Tether (USDT), how it's pegged to the US dollar, and why it matters."},content:{ar:[{type:"paragraph",text:'USDT (Tether) هي عملة رقمية مستقرة (Stablecoin) قيمتها مربوطة بالدولار الأمريكي بنسبة 1:1 تقريباً. أي أن 1 USDT ≈ 1 دولار أمريكي. أُطلقت عام 2014 تحت اسم "Realcoin" ثم تغيّر الاسم إلى Tether.'},{type:"heading",text:"كيف تظل قيمتها ثابتة؟"},{type:"paragraph",text:'تقول شركة Tether Limited أنها تحتفظ باحتياطي من الدولار الأمريكي والأصول السائلة يعادل كمية USDT المصدرة. عند إصدار 1 USDT جديد، يتم إيداع 1 دولار في الاحتياطي. هذا ما يُسمى "الربط بالدولار" (Fiat Peg).'},{type:"warning",text:"في الواقع، احتياطيات Tether ليست مدققة بالكامل بنسبة 100% نقداً. تشمل سندات حكومية، قروض، وأصول أخرى. لذلك قد تنحرف السعر قليلاً (±0.5%) في أوقات الضغط."},{type:"heading",text:"لماذا يستخدمها المصريون؟"},{type:"list",items:["حماية المدخرات من تقلبات الجنيه المصري","تحويل أموال عبر الحدود بدون قيود بنكية","التحوط من التضخم (الدولار يحافظ على قيمته أفضل من الجنيه)","وسيط لشراء عملات رقمية أخرى (Bitcoin, Ethereum)","الدفع الدولي للخدمات (Freelance, E-commerce)"]},{type:"heading",text:"الفرق بين USDT و USDC و DAI"},{type:"paragraph",text:"هناك عدة عملات مستقرة مربوطة بالدولار. USDT هي الأكبر والأكثر سيولة، لكنها الأقل شفافية. USDC تُدار بواسطة Circle وتقدم تقارير تدقيق شهري. DAI لامركزية ومربوطة بالضمانات (Collateralized) بدلاً من الاحتياطي النقدي."},{type:"example",title:"مثال واقعي",body:"إذا كان لديك 50,000 جنيه مصري وتريد حفظ قيمتها. في 2022، كان الدولار = 19 جنيه. في 2024، أصبح = 48 جنيه. لو حولت لـ USDT في 2022 (2,631 USDT)، اليوم قيمتها 2,631 × 48 = 126,288 جنيه. لو أبقيتها جنيه، ستظل 50,000 جنيه (خسرت 60% من القيمة الشرائية)."},{type:"tip",text:"USDT ليس استثماراً يربح — هو أداة حفظ قيمة. هدفه أن يكون 1 USDT = 1$ غداً وبعد سنة. الربح يأتي من التداول (شراء بسعر منخفض وبيع بسعر مرتفع)."}],en:[{type:"paragraph",text:'USDT (Tether) is a stablecoin whose value is pegged to the US dollar at approximately 1:1. 1 USDT ≈ 1 USD. It launched in 2014 as "Realcoin" and later rebranded to Tether.'},{type:"heading",text:"How does it stay stable?"},{type:"paragraph",text:'Tether Limited claims to hold reserves of USD and liquid assets equal to the amount of USDT in circulation. For every 1 USDT issued, $1 is deposited in reserve. This is called a "fiat peg."'},{type:"warning",text:"In reality, Tether's reserves are not 100% cash. They include government bonds, loans, and other assets. The price can deviate slightly (±0.5%) during stress periods."},{type:"heading",text:"Why do Egyptians use it?"},{type:"list",items:["Protecting savings from EGP volatility","Cross-border transfers without banking restrictions","Hedging against inflation","A medium to buy other cryptocurrencies (Bitcoin, Ethereum)","International payments for freelancers and e-commerce"]},{type:"heading",text:"USDT vs USDC vs DAI"},{type:"paragraph",text:"There are several dollar-pegged stablecoins. USDT is the largest and most liquid but least transparent. USDC is managed by Circle with monthly audits. DAI is decentralized and collateralized rather than cash-backed."},{type:"example",title:"Real-world example",body:"If you had 50,000 EGP in 2022 when USD = 19 EGP, and converted to USDT (2,631 USDT), today at USD = 48 EGP your holdings are worth 2,631 × 48 = 126,288 EGP. If you kept it in EGP, it would still be 50,000 EGP (losing 60% of purchasing power)."},{type:"tip",text:"USDT is not an investment that appreciates — it's a store of value. The goal is 1 USDT = $1 tomorrow and next year. Profit comes from trading (buying low, selling high)."}]}},{slug:"how-p2p-trading-works",level:"beginner",category:"p2p",icon:"🤝",readTime:8,title:{ar:"كيف يعمل التداول P2P؟ شرح نظام Escrow",en:"How P2P trading works — Escrow explained"},excerpt:{ar:"فهم آلية الضمان (Escrow) في التداول من شخص لشخص، ولماذا هي آمنة وكيف تتم الصفقة خطوة بخطوة.",en:"Understanding the Escrow mechanism in peer-to-peer trading, why it's safe, and how a trade executes step by step."},content:{ar:[{type:"paragraph",text:"التداول P2P (Peer-to-Peer) يعني بيع وشراء USDT مباشرة بين مستخدمين، وليس من المنصة نفسها. المنصة تعمل كوسيط يضمن الأمان عبر نظام الضمان (Escrow)."},{type:"heading",text:"ما هو الـ Escrow؟"},{type:"paragraph",text:'الـ Escrow هو حساب ضمان مؤقت. عندما يضع البائع USDT للبيع، يتم "تجميدها" في حساب Escrow لا يمكن لأي طرف الوصول إليه. لا تُحرر إلا بعد أن يؤكد المشتري أنه دفع الجنيه واستلم البائع المبلغ.'},{type:"heading",text:"خطوات الصفقة (مثال عملي)"},{type:"list",items:["أحمد يعرض بيع 1000 USDT بسعر 50 جنيه (يستلم 50,000 جنيه)",'سارة ترى العرض وتضغط "شراء"',"المنصة تجمد 1000 USDT من محفظة أحمد في Escrow","سارة تحوّل 50,000 جنيه إلى فودافون كاش الخاص بأحمد","سارة ترفع إيصال التحويل على المنصة","أحمد يؤكد استلام الـ 50,000 جنيه","المنصة تحرر 1000 USDT من Escrow إلى محفظة سارة","الصفقة مكتملة ✓"]},{type:"warning",text:"لا تؤكد استلام المبلغ في المنصة قبل أن تتأكد فعلاً أنه وصل إلى حسابك. بمجرد التأكيد، تُحرر USDT ولا يمكن استرجاعها."},{type:"heading",text:"ماذا لو حدث نزاع؟"},{type:"paragraph",text:"إذا ادعى المشتري أنه دفع ولم يؤكد البائع، يتم فتح نزاع (Dispute). يراجع فريق الدعم الإيصالات والسجلات. إذا أثبت المشتري الدفع عبر إيصال صحيح، تُحرر USDT له. إذا لم يكن هناك دفع، تُعاد USDT للبائع."},{type:"example",title:"مثال على احتيال شائع",body:'محتال يدعي أنه حوّل المال ويضغط "تم الدفع" على المنصة، لكنه لم يحول شيئاً. البائع المتمرس ينتظر وصول المبلغ فعلياً إلى فودافون كاش/إنستا باي قبل التأكيد. إذا لم يصل خلال 15 دقيقة، يفتح نزاعاً.'},{type:"heading",text:"رسوم P2P"},{type:"paragraph",text:"في Eg-Money، رسوم P2P هي 0.3% من قيمة الصفقة، يدفعها البائع من USDT. على صفقة 1000 USDT، الرسوم = 3 USDT، يستلم البائع 997 USDT صافي."},{type:"calculation",title:"حساب صفقة P2P",lines:[{label:"كمية USDT",value:"1,000 USDT"},{label:"السعر",value:"50 EGP/USDT"},{label:"قيمة الصفقة",value:"50,000 EGP"},{label:"رسوم المنصة (0.3%)",value:"3 USDT"}],result:"البائع يستلم: 997 USDT محفظة + 50,000 EGP فودافون"},{type:"tip",text:'تداول دائماً مع مستخدمين لديهم تقييمات عالية (نجمات) وصفقات سابقة كثيرة. تجنب العروض بأسعار "مغرية جداً" — غالباً فخ.'}],en:[{type:"paragraph",text:"P2P (Peer-to-Peer) trading means buying and selling USDT directly between users, not from the platform itself. The platform acts as an intermediary guaranteeing safety via an Escrow system."},{type:"heading",text:"What is Escrow?"},{type:"paragraph",text:"Escrow is a temporary holding account. When a seller lists USDT for sale, it's \"frozen\" in an Escrow that neither party can access. It's only released after the buyer confirms they paid EGP and the seller confirms receipt."},{type:"heading",text:"Trade steps (practical example)"},{type:"list",items:["Ahmed lists 1,000 USDT for sale at 50 EGP (receives 50,000 EGP)",'Sara sees the offer and clicks "Buy"',"Platform freezes 1,000 USDT from Ahmed's wallet in Escrow","Sara transfers 50,000 EGP to Ahmed's Vodafone Cash","Sara uploads the transfer receipt to the platform","Ahmed confirms receipt of 50,000 EGP","Platform releases 1,000 USDT from Escrow to Sara's wallet","Trade complete ✓"]},{type:"warning",text:"Never confirm receipt in the platform before verifying the money actually arrived in your account. Once confirmed, USDT is released and cannot be reversed."},{type:"heading",text:"What if there's a dispute?"},{type:"paragraph",text:"If the buyer claims they paid but the seller didn't confirm, a dispute is opened. Support reviews receipts and records. If the buyer proves payment with a valid receipt, USDT is released to them. If no payment was made, USDT is returned to the seller."},{type:"example",title:"Common scam example",body:'A scammer claims they sent money and clicks "Paid" on the platform, but sent nothing. An experienced seller waits until the money actually arrives in their Vodafone Cash/InstaPay before confirming. If it doesn\'t arrive within 15 minutes, they open a dispute.'},{type:"heading",text:"P2P fees"},{type:"paragraph",text:"On Eg-Money, the P2P fee is 0.3% of the trade value, paid by the seller from USDT. On a 1,000 USDT trade, the fee = 3 USDT, and the seller receives 997 USDT net."},{type:"calculation",title:"P2P trade calculation",lines:[{label:"USDT amount",value:"1,000 USDT"},{label:"Price",value:"50 EGP/USDT"},{label:"Trade value",value:"50,000 EGP"},{label:"Platform fee (0.3%)",value:"3 USDT"}],result:"Seller receives: 997 USDT in wallet + 50,000 EGP in Vodafone"},{type:"tip",text:'Always trade with users who have high ratings (stars) and many previous trades. Avoid offers with "too good" prices — usually a trap.'}]}},{slug:"price-spread-explained",level:"beginner",category:"basics",icon:"📊",readTime:5,title:{ar:"فهم فارق السعر (Spread) وكيف تربح المنصة",en:"Understanding the spread — how the platform earns"},excerpt:{ar:"ما هو الـ Spread؟ ولماذا سعر الشراء أعلى من سعر البيع؟ شرح بسيط لآلية الربح في منصات التداول.",en:"What is the spread? Why is the buy price higher than the sell price? A simple explanation of how trading platforms profit."},content:{ar:[{type:"paragraph",text:"الـ Spread هو الفرق بين سعر الشراء (Buy) وسعر البيع (Sell). سعر الشراء دائماً أعلى قليلاً من سعر البيع. هذا الفرق هو كيف تربح المنصة من التداول المباشر."},{type:"heading",text:"لماذا يوجد فارق؟"},{type:"paragraph",text:"المنصة تشتري USDT من السوق العالمي بأفضل سعر متاح، ثم تبيعه للمستخدمين بسعر أعلى قليلاً. الفرق هو ربح المنصة مقابل خدمة التنفيذ الفوري والسيولة."},{type:"example",title:"مثال عملي",body:"السعر في السوق العالمي الآن: شراء 49.90 جنيه، بيع 50.10 جنيه. المنصة تعرض: شراء 50.00 جنيه، بيع 49.80 جنيه. المستخدم يشتري بـ 50.00 (أعلى من 49.90 بـ 0.10). المستخدم يبيع بـ 49.80 (أقل من 50.10 بـ 0.30). الفارق الكلي = 0.20 جنيه لكل USDT."},{type:"heading",text:"حساب ربح المنصة"},{type:"calculation",title:"صفقة 1000 USDT",lines:[{label:"المستخدم يشتري 1000 USDT",value:"بسعر 50.00 = 50,000 EGP"},{label:"المنصة تشتري من السوق العالمي",value:"بسعر 49.90 = 49,900 EGP"},{label:"ربح المنصة من الصفقة",value:"100 EGP (0.2%)"}],result:"ربح المنصة = 100 جنيه على كل 1000 USDT"},{type:"heading",text:"الـ Spread في P2P vs التداول المباشر"},{type:"paragraph",text:"في التداول المباشر، الـ Spread مضمّن في السعر (0.10-0.20 جنيه/USDT). في P2P، المستخدمون يحددون الأسعار، والمنصة تأخذ عمولة 0.3% فقط. P2P أرخص لكن أبطأ، التداول المباشر أسرع لكن أغلى قليلاً."},{type:"tip",text:"إذا كنت تريد توفير المال ولديك وقت، استخدم P2P. إذا كنت تريد التنفيذ الفوري، استخدم التداول المباشر. الفرق في التكلفة على 1000 USDT ≈ 50-100 جنيه."}],en:[{type:"paragraph",text:"The spread is the difference between the buy price and sell price. The buy price is always slightly higher than the sell price. This difference is how the platform earns from direct trading."},{type:"heading",text:"Why does a spread exist?"},{type:"paragraph",text:"The platform buys USDT from the global market at the best available price, then sells it to users at a slightly higher price. The difference is the platform's profit for providing instant execution and liquidity."},{type:"example",title:"Practical example",body:"Global market price now: buy 49.90 EGP, sell 50.10 EGP. Platform shows: buy 50.00 EGP, sell 49.80 EGP. User buys at 50.00 (0.10 above 49.90). User sells at 49.80 (0.30 below 50.10). Total spread = 0.20 EGP per USDT."},{type:"heading",text:"Calculating platform profit"},{type:"calculation",title:"1,000 USDT trade",lines:[{label:"User buys 1,000 USDT",value:"at 50.00 = 50,000 EGP"},{label:"Platform buys from global market",value:"at 49.90 = 49,900 EGP"},{label:"Platform profit from trade",value:"100 EGP (0.2%)"}],result:"Platform profit = 100 EGP per 1,000 USDT"},{type:"heading",text:"Spread in P2P vs Direct trading"},{type:"paragraph",text:"In direct trading, the spread is built into the price (0.10-0.20 EGP/USDT). In P2P, users set prices and the platform takes only 0.3% commission. P2P is cheaper but slower; direct trading is faster but slightly more expensive."},{type:"tip",text:"If you want to save money and have time, use P2P. If you want instant execution, use direct trading. The cost difference on 1,000 USDT is about 50-100 EGP."}]}},{slug:"arbitrage-strategy",level:"intermediate",category:"strategy",icon:"⚖️",readTime:10,title:{ar:"استراتيجية المراجحة (Arbitrage) في سوق USDT",en:"Arbitrage strategy in the USDT market"},excerpt:{ar:"كيف تستغل فروق الأسعار بين منصات مختلفة لتحقيق ربح بدون مخاطر؟ شرح استراتيجية المراجحة مع أمثلة عملية.",en:"How to exploit price differences between platforms for risk-free profit? Arbitrage strategy explained with practical examples."},content:{ar:[{type:"paragraph",text:"المراجحة (Arbitrage) هي شراء أصل بسعر منخفض في مكان وبيعه بسعر مرتفع في مكان آخر في نفس الوقت. في سوق USDT المصري، توجد فروق أسعار بين منصات مختلفة يمكن استغلالها."},{type:"heading",text:"كيف تعمل المراجحة؟"},{type:"paragraph",text:"تقارن أسعار USDT بين منصتين. إذا كان السعر في منصة A أقل من منصة B، تشتري من A وتبيع في B. الربح = الفرق - الرسوم."},{type:"example",title:"مثال عملي",body:"منصة عالمية: سعر شراء USDT = 49.80 جنيه. Eg-Money P2P: أحد المستخدمين يعرض شراء USDT بـ 50.50 جنيه. تشتري 1000 USDT من السوق العالمي بـ 49,800 جنيه. تبيعها في Eg-Money بـ 50,500 جنيه. الربح الإجمالي = 700 جنيه. رسوم Eg-Money (0.3%) = 3 USDT ≈ 150 جنيه. صافي الربح = 550 جنيه."},{type:"heading",text:"شروط نجاح المراجحة"},{type:"list",items:["الفرق بين السعرين يجب أن يغطي الرسوم + رسوم التحويل","يجب أن يكون لديك سيولة (جنيه + USDT) في المنصتين","التنفيذ يجب أن يكون سريعاً (الأسعار تتغير كل ثانية)","احسب رسوم الإيداع/السحب لكل منصة"]},{type:"calculation",title:"حساب ربح المراجحة",lines:[{label:"شراء 1000 USDT من السوق العالمي",value:"49,800 EGP"},{label:"بيع 1000 USDT في Eg-Money",value:"50,500 EGP"},{label:"الربح الإجمالي",value:"+700 EGP"},{label:"رسوم Eg-Money (0.3%)",value:"-150 EGP"},{label:"رسوم تحويل EGP",value:"-20 EGP"}],result:"صافي الربح = 530 EGP (1.06% ربح)"},{type:"heading",text:"مخاطر المراجحة"},{type:"warning",text:"السعر قد يتغير بين شرائك وبيعك. إذا انخفض سعر البيع قبل إتمام الصفقة، قد تخسر. استخدم أوامر محددة السعر (Limit orders) عند الإمكان."},{type:"paragraph",text:"أيضاً، بعض المنصات لها حدود يومية للسحب/الإيداع. تأكد من أن السيولة متاحة في كلا المنصتين قبل البدء."},{type:"heading",text:"أدوات مساعدة"},{type:"list",items:["تطبيق CoinMarketCap لمتابعة أسعار USDT في منصات مختلفة","بوتات مراجحة (مثل Pionex) — لكنها مدفوعة ومخاطرة عالية","جداول Google لتتبع الأسعار وحساب الأرباح يدوياً"]},{type:"tip",text:"ابدأ بمبالغ صغيرة (500-1000 USDT) للتدريب. لا تستثمر كل رأس مالك في صفقة واحدة. المراجحة تتطلب صبر وانضباط."}],en:[{type:"paragraph",text:"Arbitrage is buying an asset at a low price in one place and selling it at a higher price elsewhere simultaneously. In the Egyptian USDT market, price differences exist between platforms that can be exploited."},{type:"heading",text:"How does arbitrage work?"},{type:"paragraph",text:"You compare USDT prices between two platforms. If platform A's price is lower than platform B, you buy from A and sell on B. Profit = difference - fees."},{type:"example",title:"Practical example",body:"Global platform: buy USDT at 49.80 EGP. Eg-Money P2P: a user offers to buy USDT at 50.50 EGP. You buy 1,000 USDT from the global market for 49,800 EGP. Sell on Eg-Money for 50,500 EGP. Gross profit = 700 EGP. Eg-Money fee (0.3%) = 3 USDT ≈ 150 EGP. Net profit = 550 EGP."},{type:"heading",text:"Conditions for successful arbitrage"},{type:"list",items:["The price difference must cover fees + transfer costs","You need liquidity (EGP + USDT) on both platforms","Execution must be fast (prices change every second)","Calculate deposit/withdrawal fees for each platform"]},{type:"calculation",title:"Arbitrage profit calculation",lines:[{label:"Buy 1,000 USDT from global market",value:"49,800 EGP"},{label:"Sell 1,000 USDT on Eg-Money",value:"50,500 EGP"},{label:"Gross profit",value:"+700 EGP"},{label:"Eg-Money fee (0.3%)",value:"-150 EGP"},{label:"EGP transfer fee",value:"-20 EGP"}],result:"Net profit = 530 EGP (1.06% gain)"},{type:"heading",text:"Arbitrage risks"},{type:"warning",text:"The price may change between your buy and sell. If the sell price drops before completing the trade, you could lose. Use limit orders when possible."},{type:"paragraph",text:"Also, some platforms have daily withdrawal/deposit limits. Ensure liquidity is available on both platforms before starting."},{type:"heading",text:"Helpful tools"},{type:"list",items:["CoinMarketCap app to track USDT prices across platforms","Arbitrage bots (like Pionex) — but paid and high risk","Google Sheets to track prices and calculate profits manually"]},{type:"tip",text:"Start with small amounts (500-1,000 USDT) to practice. Don't invest all your capital in one trade. Arbitrage requires patience and discipline."}]}},{slug:"dollar-cost-averaging",level:"intermediate",category:"strategy",icon:"📅",readTime:7,title:{ar:"استراتيجية المتوسط الحسابي للدولار (DCA)",en:"Dollar-Cost Averaging (DCA) strategy"},excerpt:{ar:"أفضل استراتيجية للمستثمر المبتدئ: اشترِ USDT بمبالغ ثابتة على فترات منتظمة لتقليل تأثير تقلبات السعر.",en:"The best strategy for beginner investors: buy USDT with fixed amounts at regular intervals to reduce price volatility impact."},content:{ar:[{type:"paragraph",text:'استراتيجية DCA (Dollar-Cost Averaging) تعني شراء مبلغ ثابت من USDT على فترات منتظمة (أسبوعياً، شهرياً)، بغض النظر عن السعر. الهدف هو تقليل تأثير تقلبات السعر وعدم محاولة "توقيت السوق".'},{type:"heading",text:"لماذا DCA فعّالة؟"},{type:"paragraph",text:"لا أحد يستطيع التنبؤ بالسعر بدقة. إذا اشتريت كل شيء مرة واحدة والسعر انخفض بعدها، تخسر. مع DCA، تشتري بأسعار مختلفة (أحياناً عالية، أحياناً منخفضة)، فيتوسط السعر النهائي."},{type:"example",title:"مثال عملي — 6 أشهر",body:"تقرر شراء 2000 جنيه USDT كل شهر لمدة 6 أشهر. الأسعار كانت: 48, 49, 47, 50, 48, 49. الكمية المشتراة: 41.67 + 40.82 + 42.55 + 40.00 + 41.67 + 40.82 = 247.53 USDT. لو اشتريت كل شيء (12,000 جنيه) في الشهر الأول بسعر 48، كنت ستحصل على 250 USDT. الفرق بسيط، لكنك تجنبت خطر الشراء في القمة."},{type:"heading",text:"مقارنة DCA vs الشراء مرة واحدة"},{type:"calculation",title:"سيناريو الأسعار المتذبذبة",lines:[{label:"DCA: 2000 EGP شهرياً لـ 6 أشهر",value:"247.53 USDT"},{label:"مرة واحدة: 12,000 EGP في الشهر 1 (سعر 48)",value:"250.00 USDT"},{label:"مرة واحدة: 12,000 EGP في الشهر 3 (سعر 47 - الأدنى)",value:"255.32 USDT"},{label:"مرة واحدة: 12,000 EGP في الشهر 4 (سعر 50 - الأعلى)",value:"240.00 USDT"}],result:"DCA يعطيك متوسط آمن بدون الحاجة لتوقع السوق"},{type:"heading",text:"كيف تطبق DCA على Eg-Money"},{type:"list",items:["حدد مبلغ ثابت (مثلاً 1000-5000 جنيه شهرياً)","حدد فترة منتظمة (كل أسبوع، كل شهر، كل راتب)","اشترِ USDT عبر التداول المباشر (التنفيذ الفوري)","لا تتأثر بتقلبات السعر اليومي — التزم بالخطة","راجع كل 3-6 أشهر وعدّل المبلغ إذا زاد دخلك"]},{type:"warning",text:"DCA ممتاز للحفاظ على القيمة (Hedging ضد التضخم)، لكنه ليس استراتيجية تداول نشط. لا تصلح لمن يريد أرباحاً سريعة."},{type:"heading",text:"متى تتوقف عن DCA؟"},{type:"paragraph",text:"توقف عندما: (1) تحتاج المال لشيء عاجل، (2) تغيرت أهدافك المالية، (3) وصلت لهدف ادخار محدد. لا تتوقف بسبب انخفاض السعر — هذا أفضل وقت للاستمرار (تشتري بسعر أقل)."},{type:"tip",text:"اضبط تنبيهات الأسعار على Eg-Money لتعرف أفضل أوقات الشراء. مع DCA، التوقيت المثالي ليس مهماً — الالتزام بالخطة هو الأهم."}],en:[{type:"paragraph",text:'DCA (Dollar-Cost Averaging) means buying a fixed amount of USDT at regular intervals (weekly, monthly), regardless of price. The goal is to reduce price volatility impact and avoid "timing the market."'},{type:"heading",text:"Why is DCA effective?"},{type:"paragraph",text:"No one can predict prices accurately. If you buy everything at once and the price drops, you lose. With DCA, you buy at different prices (sometimes high, sometimes low), averaging out the final price."},{type:"example",title:"Practical example — 6 months",body:"You decide to buy 2,000 EGP of USDT monthly for 6 months. Prices were: 48, 49, 47, 50, 48, 49. USDT bought: 41.67 + 40.82 + 42.55 + 40.00 + 41.67 + 40.82 = 247.53 USDT. If you bought everything (12,000 EGP) in month 1 at 48, you'd have 250 USDT. The difference is small, but you avoided the risk of buying at the peak."},{type:"heading",text:"DCA vs lump sum comparison"},{type:"calculation",title:"Volatile price scenario",lines:[{label:"DCA: 2,000 EGP monthly for 6 months",value:"247.53 USDT"},{label:"Lump sum: 12,000 EGP in month 1 (price 48)",value:"250.00 USDT"},{label:"Lump sum: 12,000 EGP in month 3 (price 47 - lowest)",value:"255.32 USDT"},{label:"Lump sum: 12,000 EGP in month 4 (price 50 - highest)",value:"240.00 USDT"}],result:"DCA gives you a safe average without needing to predict the market"},{type:"heading",text:"How to apply DCA on Eg-Money"},{type:"list",items:["Set a fixed amount (e.g., 1,000-5,000 EGP monthly)","Choose a regular interval (weekly, monthly, each payday)","Buy USDT via direct trading (instant execution)","Don't react to daily price fluctuations — stick to the plan","Review every 3-6 months and adjust the amount if your income grows"]},{type:"warning",text:"DCA is excellent for value preservation (inflation hedging), but it's not an active trading strategy. It doesn't suit those seeking quick profits."},{type:"heading",text:"When to stop DCA?"},{type:"paragraph",text:"Stop when: (1) you need money urgently, (2) your financial goals changed, (3) you reached a specific savings target. Don't stop because the price dropped — that's the best time to continue (you buy cheaper)."},{type:"tip",text:"Set price alerts on Eg-Money to know the best buying times. With DCA, perfect timing doesn't matter — sticking to the plan does."}]}},{slug:"avoiding-scams",level:"beginner",category:"security",icon:"🛡️",readTime:9,title:{ar:"كيف تحمي نفسك من الاحتيال في تداول العملات الرقمية",en:"How to protect yourself from crypto trading scams"},excerpt:{ar:"دليل شامل لأنواع الاحتيال الشائع في سوق USDT وعلامات التحذير وكيف تحمي أموالك.",en:"A comprehensive guide to common USDT market scams, warning signs, and how to protect your money."},content:{ar:[{type:"paragraph",text:"سوق العملات الرقمية يجذب المحتالين بسبب سرعة المعاملات وصعوبة استرجاع الأموال. تعرّف على أنواع الاحتيال الشائع تحمي أموالك."},{type:"heading",text:'1. احتيال "السعر المغري جداً"'},{type:"paragraph",text:"محتال يعرض بيع USDT بسعر أقل بكثير من السوق (مثلاً 45 جنيه بينما السوق 50). الهدف يجذبك لتضع أموالك قبل أن تكتشف الخدعة. بمجرد تحويل المال، يختفي."},{type:"warning",text:"القاعدة الذهبية: إذا كان العرض جيداً جداً ليكون حقيقياً، فهو احتيال. الفرق المعقول بين العروض هو 0.5-2% كحد أقصى."},{type:"heading",text:"2. احتيال الإيصال المزوّر"},{type:"paragraph",text:'المشتري يرسل إيصال تحويل مزوّر (Photoshop) ويؤكد "تم الدفع". البائع المتمرس يتحقق من حساب Vodafone Cash/InstaPay مباشرة، وليس من الإيصال فقط.'},{type:"list",items:["افتح تطبيق Vodafone Cash/InstaPay وتأكد من وصول المبلغ فعلياً","لا تعتمد على صورة الإيصال — يمكن تزويرها بسهولة","انتظر إشعار SMS من البنك/المحفظة بتأكيد الاستلام","إذا لم يصل المبلغ خلال 15 دقيقة، افتح نزاع (Dispute)"]},{type:"heading",text:"3. احتيال التحويل لخارج المنصة"},{type:"paragraph",text:'محتال يقول "حوّل لي على واتساب مباشرة، سأعطيك سعر أفضل". هذا خارج نظام Escrow — لا حماية لك. بمجرد التحويل، لا يمكنك فتح نزاع أو استرجاع المال.'},{type:"warning",text:"لا تقم بأي صفقة خارج المنصة. الـ Escrow هو حمايتك الوحيدة. أي طلب للتحويل خارج المنصة = احتيال."},{type:"heading",text:"4. احتيال الدعم الفني المزيف"},{type:"paragraph",text:"محتال يتظاهر بأنه من دعم المنصة، يطلب بيانات دخولك أو كود تحقق. الدعم الحقيقي لا يطلب أبداً كلمة المرور أو كود OTP."},{type:"heading",text:'5. احتيال "الاستثمار المضمون"'},{type:"paragraph",text:"شخص يعدك بأرباح يومية مضمونة (5%, 10%) مقابل إيداع USDT. هذا مخطط بونزي — يدفع الأرباح الأولى من أموال المستثمرين الجدد، ثم ينهار."},{type:"example",title:"مثال واقعي",body:'صفحة فيسبوك تدعي "استثمر 1000 USDT واحصل على 1500 بعد أسبوع". في البداية يدفعون لأشخاص قليل لإقناع آخرين. بعد تجميع مبالغ كبيرة، يختفون. هذه ليست تداول — هذه سرقة.'},{type:"heading",text:"علامات تحذير يجب الانتباه لها"},{type:"list",items:["أسعار تختلف عن السوق بأكثر من 3%",'ضغط لإتمام الصفقة بسرعة ("العرض ينتهي خلال ساعة")',"طلب التحويل خارج المنصة","طلب بيانات دخولك أو أكواد تحقق","وعود بأرباح مضمونة بدون مخاطر","صفحات التواصل الاجتماعي بدون تقييمات حقيقية"]},{type:"heading",text:"كيف تحمي نفسك"},{type:"list",items:["تداول دائماً داخل المنصة مع Escrow مفعّل","تحقق من تقييمات الطرف الآخر وعدد صفقاته السابقة","لا تتعجل — الصفقات الجيدة لا تختفي في ثانية","فعّل المصادقة الثنائية (2FA) على حسابك","لا تشارك كلمة المرور أو كود OTP مع أحد أبداً","بلغ عن أي سلوك مشبوه فوراً"]},{type:"tip",text:"المنصة الموثوقة لا تطلب أبداً تحويل أموال خارج نظامها. الـ Escrow هو خط الدفاع الأول — استخدمه دائماً."}],en:[{type:"paragraph",text:"The cryptocurrency market attracts scammers due to fast transactions and difficulty recovering funds. Knowing common scam types protects your money."},{type:"heading",text:'1. The "too good to be true" price scam'},{type:"paragraph",text:"A scammer offers USDT well below market (e.g., 45 EGP while market is 50). The goal is to lure you into sending money before discovering the trick. Once paid, they disappear."},{type:"warning",text:"Golden rule: if an offer seems too good to be true, it's a scam. Reasonable offer differences are 0.5-2% maximum."},{type:"heading",text:"2. Fake receipt scam"},{type:"paragraph",text:'The buyer sends a forged (Photoshopped) transfer receipt and confirms "Paid." An experienced seller checks their Vodafone Cash/InstaPay app directly, not just the receipt.'},{type:"list",items:["Open Vodafone Cash/InstaPay app and verify the money actually arrived","Don't rely on receipt images — easily forged","Wait for SMS notification from bank/wallet confirming receipt","If money doesn't arrive within 15 minutes, open a dispute"]},{type:"heading",text:"3. Off-platform transfer scam"},{type:"paragraph",text:"A scammer says \"transfer to me directly on WhatsApp, I'll give you a better price.\" This bypasses the Escrow system — you have no protection. Once transferred, you can't dispute or recover funds."},{type:"warning",text:"Never do any trade outside the platform. Escrow is your only protection. Any request to transfer off-platform = scam."},{type:"heading",text:"4. Fake support agent scam"},{type:"paragraph",text:"A scammer impersonates platform support, asking for your login details or verification code. Real support never asks for your password or OTP code."},{type:"heading",text:'5. "Guaranteed investment" scam'},{type:"paragraph",text:"Someone promises guaranteed daily returns (5%, 10%) for depositing USDT. This is a Ponzi scheme — early payouts come from new investors' money, then it collapses."},{type:"example",title:"Real-world example",body:"A Facebook page claims \"Invest 1,000 USDT and get 1,500 after a week.\" Initially they pay a few people to convince others. After collecting large amounts, they vanish. This isn't trading — it's theft."},{type:"heading",text:"Warning signs to watch for"},{type:"list",items:["Prices differing from market by more than 3%",'Pressure to complete quickly ("offer ends in an hour")',"Requests to transfer off-platform","Requests for your login details or verification codes","Promises of guaranteed risk-free returns","Social media pages with no real reviews"]},{type:"heading",text:"How to protect yourself"},{type:"list",items:["Always trade within the platform with Escrow enabled","Check the other party's rating and number of past trades","Don't rush — good trades don't disappear in a second","Enable two-factor authentication (2FA) on your account","Never share your password or OTP code with anyone","Report any suspicious behavior immediately"]},{type:"tip",text:"A trustworthy platform never asks you to transfer funds outside its system. Escrow is your first line of defense — always use it."}]}},{slug:"egypt-economic-context",level:"intermediate",category:"economy",icon:"🇪🇬",readTime:8,title:{ar:"لماذا يلجأ المصريون لـ USDT؟ السياق الاقتصادي",en:"Why do Egyptians turn to USDT? The economic context"},excerpt:{ar:"تحليل واقعي لأسباب لجوء المصريين لـ USDT: التضخم، تخفيض الجنيه، القيود على النقد الأجنبي.",en:"A realistic analysis of why Egyptians turn to USDT: inflation, EGP devaluation, foreign currency restrictions."},content:{ar:[{type:"paragraph",text:"اللجوء المصري لـ USDT ليس مضاربة بل ضرورة اقتصادية. فهم السياق يساعدك على اتخاذ قرارات مالية أفضل."},{type:"heading",text:"1. تخفيض الجنيه المصري"},{type:"paragraph",text:"من 2016 لـ 2024، تخفض الجنيه عدة مرات: من 8.88 (2016) إلى 19 (2022) إلى 48 (2024) مقابل الدولار. كل تخفيض يفقد الجنيه 30-50% من قيمته. من يحتفظ بـ USDT يحمي مدخراته من هذا التآكل."},{type:"calculation",title:"تآكل قيمة الجنيه",lines:[{label:"100,000 EGP في 2016 (سعر 8.88)",value:"= 11,261 $"},{label:"100,000 EGP في 2022 (سعر 19)",value:"= 5,263 $"},{label:"100,000 EGP في 2024 (سعر 48)",value:"= 2,083 $"}],result:"القيمة الشرائية بالدولار انخفضت 81% خلال 8 سنوات"},{type:"heading",text:"2. التضخم المحلي"},{type:"paragraph",text:"معدل التضخم في مصر وصل لـ 30-40% في 2023-2024. الأسعار تتضاعف كل 2-3 سنوات. الجنيه في البنك يفقد قيمته يومياً، بينما USDT مربوط بالدولار الذي تضخمه 2-3% سنوياً فقط."},{type:"heading",text:"3. القيود على النقد الأجنبي"},{type:"paragraph",text:"البنوك المصرية تفرض قيوداً على شراء الدولار: حد أقصى شهري، مستندات، موافقات. USDT يوفر بديلاً سريعاً بدون قيود — تشتري وتبيع في دقائق."},{type:"heading",text:"4. تحويلات العاملين بالخارج"},{type:"paragraph",text:"المصريون العاملون بالخارج يحتاجون لإرسال أموال للعائلة. التحويل البنكي بطيء ومكلف. USDT عبر P2P أسرع وأرخص: تحويل من محفظة لأخرى خلال دقائق، رسوم 0.3%."},{type:"example",title:"مثال: عامل في السعودية",body:"أحمد يعمل في السعودية ويرسل 5000 ريال شهرياً لعائلته. عبر البنك: 3-5 أيام عمل، رسوم 2-3%. عبر USDT: يحول ريالات لـ USDT، يرسلها لمحفظة عائلته على Eg-Money، تبيع USDT لجنيه. إجمالي الوقت: 10 دقائق. الرسوم: 0.6% (شراء + بيع)."},{type:"heading",text:"5. التجارة الإلكترونية والـ Freelance"},{type:"paragraph",text:"المصريون الذين يعملون أونلاين (Upwork, Fiverr) يتقاضون بالدولار. تحويل البنكي للجنيه يخسر من سعر الصرف والرسوم. USDT يوفر استلام مباشر بسعر السوق."},{type:"heading",text:"مخاطر الاحتفاظ بـ USDT"},{type:"warning",text:"USDT ليس خالي المخاطر: (1) مخاطر تنظيمية — الحكومة قد تقيّد استخدامه، (2) مخاطر تقنية — اختراق المحفظة أو فقدان المفتاح، (3) مخاطر الاحتياطي — Tether قد تواجه مشاكل قانونية. لا تضع كل مدخراتك في USDT — نوّع."},{type:"heading",text:"الخلاصة العملية"},{type:"list",items:["احتفظ بـ 30-50% من مدخراتك في USDT للحماية من التضخم","أبقِ 20-30% بالجنيه للمصاريف اليومية والطارئة","نوّع الباقي في أصول أخرى (ذهب، شهادات إيداع)","راقب الأخبار الاقتصادية — التخفيضات تحدث فجأة","لا تحول كل أموالك دفعة واحدة — استخدم DCA"]},{type:"tip",text:'الهدف من USDT ليس الثراء السريع بل الحفاظ على قيمة كدهبك. فكر فيه كـ "حساب دولاري" بدون قيود بنكية.'}],en:[{type:"paragraph",text:"Egyptians turning to USDT isn't speculation — it's economic necessity. Understanding the context helps you make better financial decisions."},{type:"heading",text:"1. Egyptian pound devaluation"},{type:"paragraph",text:"From 2016 to 2024, the EGP was devalued multiple times: from 8.88 (2016) to 19 (2022) to 48 (2024) against the dollar. Each devaluation costs the pound 30-50% of its value. Holding USDT protects savings from this erosion."},{type:"calculation",title:"EGP value erosion",lines:[{label:"100,000 EGP in 2016 (rate 8.88)",value:"= $11,261"},{label:"100,000 EGP in 2022 (rate 19)",value:"= $5,263"},{label:"100,000 EGP in 2024 (rate 48)",value:"= $2,083"}],result:"Dollar purchasing power dropped 81% in 8 years"},{type:"heading",text:"2. Local inflation"},{type:"paragraph",text:"Egypt's inflation rate reached 30-40% in 2023-2024. Prices double every 2-3 years. Money in the bank loses value daily, while USDT is pegged to the dollar which has only 2-3% annual inflation."},{type:"heading",text:"3. Foreign currency restrictions"},{type:"paragraph",text:"Egyptian banks impose restrictions on buying dollars: monthly caps, documentation, approvals. USDT offers a quick alternative without restrictions — buy and sell in minutes."},{type:"heading",text:"4. Remittances from abroad"},{type:"paragraph",text:"Egyptians working abroad need to send money home. Bank transfers are slow and expensive. USDT via P2P is faster and cheaper: wallet-to-wallet transfer in minutes, 0.3% fees."},{type:"example",title:"Example: Worker in Saudi Arabia",body:"Ahmed works in Saudi Arabia and sends 5,000 SAR monthly to his family. Via bank: 3-5 business days, 2-3% fees. Via USDT: converts SAR to USDT, sends to family's Eg-Money wallet, they sell USDT for EGP. Total time: 10 minutes. Fees: 0.6% (buy + sell)."},{type:"heading",text:"5. E-commerce and Freelance"},{type:"paragraph",text:"Egyptians working online (Upwork, Fiverr) earn in dollars. Bank conversion to EGP loses on exchange rate and fees. USDT offers direct receipt at market price."},{type:"heading",text:"Risks of holding USDT"},{type:"warning",text:"USDT isn't risk-free: (1) regulatory risk — government may restrict it, (2) technical risk — wallet hacking or lost keys, (3) reserve risk — Tether may face legal issues. Don't put all your savings in USDT — diversify."},{type:"heading",text:"Practical conclusion"},{type:"list",items:["Keep 30-50% of savings in USDT for inflation protection","Keep 20-30% in EGP for daily and emergency expenses","Diversify the rest in other assets (gold, certificates)","Monitor economic news — devaluations happen suddenly","Don't convert all your money at once — use DCA"]},{type:"tip",text:"The goal of USDT isn't quick wealth but preserving your money's value. Think of it as a \"dollar account\" without banking restrictions."}]}},{slug:"risk-management",level:"intermediate",category:"risk",icon:"⚠️",readTime:8,title:{ar:"إدارة المخاطر: لا تخسر كل أموالك",en:"Risk management: don't lose all your money"},excerpt:{ar:"قواعد ذهبية لإدارة المخاطر في التداول: قاعدة 1%, وقف الخسارة, التنويع, وإدارة رأس المال.",en:"Golden rules for trading risk management: the 1% rule, stop-loss, diversification, and capital management."},content:{ar:[{type:"paragraph",text:"إدارة المخاطر هي الفرق بين التاجر الناجح والفاشل. ليس مهم كم تربح، بل كم لا تخسر. التداول بدون إدارة مخاطر = قمار."},{type:"heading",text:"القاعدة الذهبية: لا تخاطر بأكثر من 1-2%"},{type:"paragraph",text:"في كل صفقة، لا تخاطر بأكثر من 1-2% من رأس مالك. إذا كان رأس مالك 50,000 جنيه، الحد الأقصى للخسارة في صفقة واحدة = 500-1000 جنيه. بهذا، حتى لو خسرت 10 صفقات متتالية (نادر جداً)، يبقى لديك 90% من رأس مالك."},{type:"calculation",title:"حساب حجم المخاطرة",lines:[{label:"رأس المال",value:"50,000 EGP"},{label:"نسبة المخاطرة (1%)",value:"500 EGP"},{label:"سعر USDT",value:"50 EGP"},{label:"أقصى كمية تخسرها",value:"10 USDT"}],result:"إذا كان وقف الخسارة 0.5 جنيه، حجم الصفقة = 20 USDT (1000 EGP)"},{type:"heading",text:"قاعدة وقف الخسارة (Stop-Loss)"},{type:"paragraph",text:"قبل دخول أي صفقة، حدد السعر الذي ستخرج عنده إذا خسرت. مثلاً: تشتري USDT بـ 50 جنيه، تضع وقف خسارة عند 49.5. إذا انخفض السعر لـ 49.5، تبيع تلقائياً وتخسر 0.5 جنيه فقط لكل USDT."},{type:"warning",text:"لا تحرك وقف الخسارة لأسفل أبداً. إذا كان السعر يصل لوقف الخسارة، اخرج. تحريك الوقف = خسائر أكبر."},{type:"heading",text:"التنويع (Diversification)"},{type:"paragraph",text:"لا تضع كل أموالك في صفقة واحدة أو استراتيجية واحدة. نوّع:"},{type:"list",items:["60-70% استثمار طويل المدى (DCA في USDT)","20-30% تداول نشط (P2P, مراجحة)","10% نقد/جنيه للفرص الطارئة","لا تتجاوز 5% في صفقة واحدة"]},{type:"heading",text:"نسبة المخاطرة/العائد (Risk/Reward)"},{type:"paragraph",text:"قبل كل صفقة، احسب النسبة. مثلاً: تخاطر بـ 500 جنيه (وقف خسارة) لتكسب 1500 جنيه (هدف). النسبة = 1:3. هذه صفقة جيدة. حتى لو خسرت 2 من 3 صفقات، أنت مربح."},{type:"calculation",title:"مثال نسبة 1:3",lines:[{label:"صفقة 1: ربح",value:"+1,500 EGP"},{label:"صفقة 2: خسارة",value:"-500 EGP"},{label:"صفقة 3: خسارة",value:"-500 EGP"},{label:"صفقة 4: ربح",value:"+1,500 EGP"}],result:"الصافي = +2,000 EGP (50% نجاح لكن ربح إجمالي)"},{type:"heading",text:"قاعدة عدم التداول العاطفي"},{type:"paragraph",text:"الخوف والطمع هما أعداء المتداول. لا تبيع بخوف عند أول انخفاض، ولا تشتري بطمع عند أول ارتفاع. التزم بخطتك ووقف الخسارة."},{type:"list",items:["لا تتداول وأنت غاضب أو متعب","لا تطارد خسائرك (محاولة تعويض بسرعة = خسائر أكبر)","لا تزيد حجم الصفقة بعد ربح (Overconfidence)","سجّل كل صفقة وسببها لتتعلم من أخطائك"]},{type:"tip",text:"المتداول الناجح ليس من يربح في كل صفقة، بل من يخسر قليلاً ويربح كثيراً. إدارة المخاطر هي ما يبقيك في اللعبة طويلاً."}],en:[{type:"paragraph",text:"Risk management is the difference between successful and failed traders. It's not about how much you earn, but how much you don't lose. Trading without risk management = gambling."},{type:"heading",text:"Golden rule: never risk more than 1-2%"},{type:"paragraph",text:"In each trade, never risk more than 1-2% of your capital. If your capital is 50,000 EGP, the maximum loss per trade = 500-1,000 EGP. This way, even if you lose 10 consecutive trades (very rare), you still have 90% of your capital."},{type:"calculation",title:"Risk size calculation",lines:[{label:"Capital",value:"50,000 EGP"},{label:"Risk percentage (1%)",value:"500 EGP"},{label:"USDT price",value:"50 EGP"},{label:"Max loss amount",value:"10 USDT"}],result:"If stop-loss is 0.5 EGP, trade size = 20 USDT (1,000 EGP)"},{type:"heading",text:"Stop-loss rule"},{type:"paragraph",text:"Before entering any trade, set the price at which you'll exit if losing. For example: buy USDT at 50 EGP, set stop-loss at 49.5. If price drops to 49.5, sell automatically and lose only 0.5 EGP per USDT."},{type:"warning",text:"Never move your stop-loss down. If price hits stop-loss, exit. Moving the stop = bigger losses."},{type:"heading",text:"Diversification"},{type:"paragraph",text:"Don't put all your money in one trade or one strategy. Diversify:"},{type:"list",items:["60-70% long-term investment (DCA in USDT)","20-30% active trading (P2P, arbitrage)","10% cash/EGP for emergency opportunities","Never exceed 5% in a single trade"]},{type:"heading",text:"Risk/Reward ratio"},{type:"paragraph",text:"Before each trade, calculate the ratio. For example: risk 500 EGP (stop-loss) to earn 1,500 EGP (target). Ratio = 1:3. This is a good trade. Even if you lose 2 of 3 trades, you're profitable."},{type:"calculation",title:"1:3 ratio example",lines:[{label:"Trade 1: profit",value:"+1,500 EGP"},{label:"Trade 2: loss",value:"-500 EGP"},{label:"Trade 3: loss",value:"-500 EGP"},{label:"Trade 4: profit",value:"+1,500 EGP"}],result:"Net = +2,000 EGP (50% success but overall profit)"},{type:"heading",text:"No emotional trading"},{type:"paragraph",text:"Fear and greed are traders' enemies. Don't sell out of fear at the first drop, and don't buy out of greed at the first rise. Stick to your plan and stop-loss."},{type:"list",items:["Don't trade when angry or tired","Don't chase losses (trying to recover quickly = bigger losses)","Don't increase trade size after a win (overconfidence)","Log every trade and its reason to learn from mistakes"]},{type:"tip",text:"A successful trader isn't one who wins every trade, but one who loses little and earns much. Risk management keeps you in the game long-term."}]}},{slug:"technical-analysis-basics",level:"advanced",category:"strategy",icon:"📈",readTime:11,title:{ar:"أساسيات التحليل الفني لسوق USDT",en:"Technical analysis basics for the USDT market"},excerpt:{ar:"مقدمة في قراءة الرسوم البيانية، خطوط الدعم والمقاومة, المتوسطات المتحركة, وكيف تستخدمها في قرارات التداول.",en:"Introduction to reading charts, support and resistance lines, moving averages, and how to use them in trading decisions."},content:{ar:[{type:"paragraph",text:"التحليل الفني (Technical Analysis) هو دراسة حركة السعر عبر الرسوم البيانية للتنبؤ بالاتجاه المستقبلي. لا يتنبأ بالمستقبل بدقة 100%، لكنه يساعد في اتخاذ قرارات مدروسة بدلاً من عشوائية."},{type:"heading",text:"1. خطوط الدعم والمقاومة"},{type:"paragraph",text:"الدعم (Support) هو سعر يجد فيه الطلب كافياً لمنع المزيد من الانخفاض. المقاومة (Resistance) هو سعر يجد فيه العرض كافياً لمنع المزيد من الارتفاع."},{type:"example",title:"مثال عملي",body:"سعر USDT يتذبذب بين 48 و 51 جنيه لمدة شهر. 48 = دعم (كلما وصل، يعود للارتفاع). 51 = مقاومة (كلما وصل، يعود للانخفاض). استراتيجية: شراء عند 48-49, بيع عند 50-51."},{type:"heading",text:"2. المتوسطات المتحركة (Moving Averages)"},{type:"paragraph",text:"المتوسط المتحرك يحسب متوسط السعر خلال فترة معينة. الأكثر استخداماً: MA-7 (أسبوع), MA-30 (شهر), MA-90 (3 أشهر). عندما يقطع MA-7 خط MA-30 للأعلى = إشارة شراء. للأسفل = إشارة بيع."},{type:"example",title:"إشارة تقاطع",body:"USDT كان سعره 49 جنيه. MA-7 = 49.5, MA-30 = 50.5. السعر بدأ يرتفع و MA-7 قطع MA-30 للأعلى. إشارة شراء. بعد أسبوع، السعر وصل 51. هذا ربح 2 جنيه/USDT."},{type:"heading",text:"3. مؤشر RSI (القوة النسبية)"},{type:"paragraph",text:"RSI يقيس قوة الحركة من 0-100. فوق 70 = تشبع شرائي (السعر مرتفع جداً، قد ينخفض). تحت 30 = تشبع بيعي (السعر منخفض جداً، قد يرتفع). في سوق USDT المصري، RSI مفيد لكن ليس حاسماً لأن السعر مربوط بالدولار."},{type:"heading",text:"4. حجم التداول (Volume)"},{type:"paragraph",text:"الحجم يؤكد قوة الحركة. إذا ارتفع السعر بحجم كبير = حركة قوية ومستدامة. إذا ارتفع بحجم ضعيف = قد تكون حركة مؤقتة. راقب حجم الصفقات على Eg-Money P2P."},{type:"heading",text:"5. الأنماط (Patterns)"},{type:"list",items:["رأس وكتفان (Head & Shoulders): نمط انعكاسي — بعد اكتماله، ينعكس الاتجاه","مثلث صاعد (Ascending Triangle): استمراري — السعر يكمل في اتجاه الصعود","قمة مزدوجة (Double Top): السعر يصطدم بنفس المقاومة مرتين ثم ينخفض","قاع مزدوج (Double Bottom): السعر يصطدم بنفس الدعم مرتين ثم يرتفع"]},{type:"warning",text:"التحليل الفني ليس سحراً. الأنماط قد تنكسر. استخدمه كأداة مساعدة وليس كنبوءة. ادمجه مع إدارة المخاطر ووقف الخسارة."},{type:"heading",text:"كيف تطبق التحليل الفني على Eg-Money"},{type:"list",items:["استخدم الرسم البياني في صفحة التداول لرؤية حركة السعر","ارسم خطوط الدعم والمقاومة على فترة 7-30 يوم","راقب تقاطعات المتوسطات المتحركة","لا تتداول بناءً على إشارة واحدة — ابحث عن تأكيدات","سجّل توقعاتك وراجعها لاحقاً لقياس دقتك"]},{type:"calculation",title:"مثال صفقة مبنية على تحليل",lines:[{label:"الدعم الحالي",value:"48 EGP"},{label:"المقاومة الحالية",value:"51 EGP"},{label:"السعر الحالي",value:"49 EGP (قرب الدعم)"},{label:"هدف الربح",value:"50.5 EGP (قرب المقاومة)"},{label:"وقف الخسارة",value:"47.5 EGP (أسفل الدعم)"}],result:"مخاطرة 1.5 جنيه / عائد محتمل 1.5 جنيه = نسبة 1:1 (مقبولة)"},{type:"tip",text:"التحليل الفني يعمل بشكل أفضل في الأسواق ذات السيولة العالية. سوق USDT المصري صغير نسبياً، لذا قد تكون الإشارات أقل دقة. ادمج التحليل الفني مع التحليل الأساسي (الأخبار الاقتصادية)."}],en:[{type:"paragraph",text:"Technical Analysis is the study of price movement through charts to predict future direction. It doesn't predict the future with 100% accuracy, but helps make informed decisions rather than random ones."},{type:"heading",text:"1. Support and resistance lines"},{type:"paragraph",text:"Support is a price where demand is strong enough to stop further decline. Resistance is a price where supply is strong enough to stop further rise."},{type:"example",title:"Practical example",body:"USDT price oscillates between 48 and 51 EGP for a month. 48 = support (whenever it reaches, it bounces back up). 51 = resistance (whenever it reaches, it drops back). Strategy: buy at 48-49, sell at 50-51."},{type:"heading",text:"2. Moving Averages"},{type:"paragraph",text:"A moving average calculates the average price over a period. Most used: MA-7 (week), MA-30 (month), MA-90 (3 months). When MA-7 crosses MA-30 upward = buy signal. Downward = sell signal."},{type:"example",title:"Crossover signal",body:"USDT was at 49 EGP. MA-7 = 49.5, MA-30 = 50.5. Price started rising and MA-7 crossed MA-30 upward. Buy signal. A week later, price reached 51. That's a 2 EGP/USDT profit."},{type:"heading",text:"3. RSI (Relative Strength Index)"},{type:"paragraph",text:"RSI measures momentum from 0-100. Above 70 = overbought (price too high, may drop). Below 30 = oversold (price too low, may rise). In the Egyptian USDT market, RSI is useful but not decisive since the price is dollar-pegged."},{type:"heading",text:"4. Volume"},{type:"paragraph",text:"Volume confirms move strength. If price rises with high volume = strong, sustainable move. If it rises with low volume = may be temporary. Watch trade volume on Eg-Money P2P."},{type:"heading",text:"5. Patterns"},{type:"list",items:["Head & Shoulders: reversal pattern — after completion, trend reverses","Ascending Triangle: continuation — price continues upward","Double Top: price hits same resistance twice then drops","Double Bottom: price hits same support twice then rises"]},{type:"warning",text:"Technical analysis isn't magic. Patterns can break. Use it as a helper, not a prophecy. Combine it with risk management and stop-loss."},{type:"heading",text:"How to apply TA on Eg-Money"},{type:"list",items:["Use the trading page chart to see price movement","Draw support/resistance lines on 7-30 day periods","Watch moving average crossovers","Don't trade on a single signal — look for confirmations","Log your predictions and review later to measure accuracy"]},{type:"calculation",title:"Analysis-based trade example",lines:[{label:"Current support",value:"48 EGP"},{label:"Current resistance",value:"51 EGP"},{label:"Current price",value:"49 EGP (near support)"},{label:"Profit target",value:"50.5 EGP (near resistance)"},{label:"Stop-loss",value:"47.5 EGP (below support)"}],result:"Risk 1.5 EGP / potential return 1.5 EGP = 1:1 ratio (acceptable)"},{type:"tip",text:"Technical analysis works best in highly liquid markets. The Egyptian USDT market is relatively small, so signals may be less accurate. Combine TA with fundamental analysis (economic news)."}]}},{slug:"payment-methods-guide",level:"beginner",category:"p2p",icon:"💳",readTime:6,title:{ar:"دليل طرق الدفع المصرية: فودافون كاش، إنستا باي، فوري",en:"Guide to Egyptian payment methods: Vodafone Cash, InstaPay, Fawry"},excerpt:{ar:"مقارنة شاملة بين طرق الدفع المتاحة، الرسوم، السرعة، وحدود التحويل لكل منها.",en:"A comprehensive comparison of available payment methods, fees, speed, and transfer limits for each."},content:{ar:[{type:"paragraph",text:"عند التداول على Eg-Money، تختار طريقة دفع لإيداع/سحب الجنيه. كل طريقة لها مميزاتها وعيوبها. إليك المقارنة الكاملة."},{type:"heading",text:"1. فودافون كاش (Vodafone Cash)"},{type:"list",items:["السرعة: فوري (ثوانٍ)","الرسوم: 1% للتحويل لغير فودافون، مجاني لفودافون","الحد اليومي: 60,000 جنيه (حسب فئة الحساب)","الحد الشهري: 200,000 جنيه","الانتشار: الأكثر شيوعاً في مصر"]},{type:"paragraph",text:"الأفضل للصفقات الصغيرة والمتوسطة (حتى 30,000 جنيه). سريع جداً ومناسب لـ P2P."},{type:"heading",text:"2. إنستا باي (InstaPay)"},{type:"list",items:["السرعة: فوري (ثوانٍ)","الرسوم: مجاني تماماً (حتى 100,000 جنيه شهرياً)","الحد اليومي: 60,000-250,000 جنيه (حسب البنك)","الحد الشهري: 200,000-6,000,000 جنيه","الانتشار: متزايد، يحتاج حساب بنكي"]},{type:"paragraph",text:"الأفضل للصفقات الكبيرة (فوق 30,000 جنيه). مجاني وحدود أعلى، لكن يحتاج حساب بنكي."},{type:"heading",text:"3. فوري (Fawry)"},{type:"list",items:["السرعة: فوري (دقائق)","الرسوم: 5-10 جنيه لكل عملية","الحد اليومي: 6,000 جنيه للإيداع، 30,000 للسحب","الانتشار: واسع جداً، متاح في 200,000 منفذ"]},{type:"paragraph",text:"الأفضل للصفقات الصغيرة جداً (حتى 6,000 جنيه). مناسب لمن ليس لديه حساب بنكي أو فودافون كاش."},{type:"heading",text:"4. التحويل البنكي"},{type:"list",items:["السرعة: 1-3 أيام عمل (محلي)، فوري (نفس البنك)","الرسوم: 5-50 جنيه حسب البنك","الحد: لا يوجد (حسب سياسة البنك)","الانتشار: متطلب لمستندات"]},{type:"paragraph",text:"الأفضل للصفقات الكبيرة جداً (فوق 100,000 جنيه) حيث فودافون كاش وإنستا باي لها حدود."},{type:"calculation",title:"مقارنة رسوم صفقة 50,000 جنيه",lines:[{label:"فودافون كاش → فودافون كاش",value:"مجاني"},{label:"فودافون كاش → بنك",value:"500 EGP (1%)"},{label:"إنستا باي",value:"مجاني"},{label:"فوري",value:"10 EGP"},{label:"تحويل بنكي",value:"20-50 EGP"}],result:"إنستا باي الأرخص للصفقات الكبيرة"},{type:"heading",text:"نصائح لاختيار طريقة الدفع"},{type:"list",items:["صفقات أقل من 6,000 جنيه: فودافون كاش أو فوري","صفقات 6,000-30,000 جنيه: فودافون كاش","صفقات 30,000-200,000 جنيه: إنستا باي (مجاني + حدود عالية)","صفقات فوق 200,000 جنيه: تحويل بنكي متعدد","دائماً احتفظ بأكثر من طريقة كاحتياط"]},{type:"warning",text:"لا تستخدم طريقة دفع ليست باسمك. إذا اكتشفت المنصة عدم تطابق الأسماء، قد تُجمّد حسابك للاشتباه."},{type:"tip",text:"فعّل إشعارات Vodafone Cash و InstaPay لتتأكد فوراً من وصول المال في صفقات P2P. لا تعتمد على إشعار الطرف الآخر."}],en:[{type:"paragraph",text:"When trading on Eg-Money, you choose a payment method to deposit/withdraw EGP. Each method has pros and cons. Here's the full comparison."},{type:"heading",text:"1. Vodafone Cash"},{type:"list",items:["Speed: instant (seconds)","Fees: 1% for non-Vodafone transfers, free for Vodafone","Daily limit: 60,000 EGP (depending on account tier)","Monthly limit: 200,000 EGP","Adoption: most widespread in Egypt"]},{type:"paragraph",text:"Best for small-to-medium trades (up to 30,000 EGP). Very fast and suitable for P2P."},{type:"heading",text:"2. InstaPay"},{type:"list",items:["Speed: instant (seconds)","Fees: completely free (up to 100,000 EGP monthly)","Daily limit: 60,000-250,000 EGP (depending on bank)","Monthly limit: 200,000-6,000,000 EGP","Adoption: growing, requires bank account"]},{type:"paragraph",text:"Best for large trades (above 30,000 EGP). Free with higher limits, but requires a bank account."},{type:"heading",text:"3. Fawry"},{type:"list",items:["Speed: instant (minutes)","Fees: 5-10 EGP per transaction","Daily limit: 6,000 EGP for deposits, 30,000 for withdrawals","Adoption: very wide, available at 200,000 outlets"]},{type:"paragraph",text:"Best for very small trades (up to 6,000 EGP). Suitable for those without bank accounts or Vodafone Cash."},{type:"heading",text:"4. Bank transfer"},{type:"list",items:["Speed: 1-3 business days (domestic), instant (same bank)","Fees: 5-50 EGP depending on bank","Limit: none (depending on bank policy)","Adoption: requires documentation"]},{type:"paragraph",text:"Best for very large trades (above 100,000 EGP) where Vodafone Cash and InstaPay have limits."},{type:"calculation",title:"Fee comparison for 50,000 EGP trade",lines:[{label:"Vodafone Cash → Vodafone Cash",value:"Free"},{label:"Vodafone Cash → Bank",value:"500 EGP (1%)"},{label:"InstaPay",value:"Free"},{label:"Fawry",value:"10 EGP"},{label:"Bank transfer",value:"20-50 EGP"}],result:"InstaPay is cheapest for large trades"},{type:"heading",text:"Tips for choosing a payment method"},{type:"list",items:["Trades under 6,000 EGP: Vodafone Cash or Fawry","Trades 6,000-30,000 EGP: Vodafone Cash","Trades 30,000-200,000 EGP: InstaPay (free + high limits)","Trades above 200,000 EGP: multiple bank transfers","Always keep more than one method as backup"]},{type:"warning",text:"Don't use a payment method not in your name. If the platform discovers name mismatch, your account may be frozen for suspicion."},{type:"tip",text:"Enable Vodafone Cash and InstaPay notifications to instantly confirm money arrival in P2P trades. Don't rely on the other party's notification."}]}},{slug:"taxes-and-legal",level:"advanced",category:"economy",icon:"⚖️",readTime:7,title:{ar:"الضرائب والقوانين: الوضع القانوني لـ USDT في مصر",en:"Taxes and laws: the legal status of USDT in Egypt"},excerpt:{ar:"ماذا يقول القانون المصري عن تداول العملات الرقمية؟ هل تدفع ضرائب؟ مخاطر قانونية يجب معرفتها.",en:"What does Egyptian law say about crypto trading? Do you pay taxes? Legal risks you should know."},content:{ar:[{type:"paragraph",text:"الوضع القانوني للعملات الرقمية في مصر معقد وغير واضح تماماً. هذا المقال يلخص الوضع الحالي حتى تاريخ نشره — استشر محامياً للاستشارة الخاصة."},{type:"warning",text:"هذا المقال للمعلومات العامة فقط وليس استشارة قانونية. القوانين تتغير. راجع محامياً مختصاً قبل اتخاذ قرارات مالية كبيرة."},{type:"heading",text:"موقف البنك المركزي المصري"},{type:"paragraph",text:"في 2018، أصدر البنك المركزي تحذيراً من العملات الرقمية، لكنه لم يحظرها صراحة. في 2020، أقر قانون البنك المركزي والجهاز المصرفي الذي يجرم إصدار أو ترويج عملات رقمية بدون ترخيص. لكن التداول الشخصي بين الأفراد ليس محظوراً صراحة."},{type:"heading",text:"موقف هيئة الرقابة المالية"},{type:"paragraph",text:"هيئة الرقابة المالية تنظم منصات التداول المرخصة. معظم منصات العملات الرقمية العاملة في مصر غير مرخصة. هذا يضع المستخدم في منطقة رمادية قانونياً."},{type:"heading",text:"الضرائب على الأرباح"},{type:"paragraph",text:"قانونياً، أي ربح من تداول الأصول يخضع لضريبة الدخل. لكن في الواقع، لا توجد آلية واضحة للإبلاغ عن أرباح العملات الرقمية. إذا حولت أرباحاً كبيرة لجنيه عبر بنك، قد يطلب البنك مصدر الأموال."},{type:"list",items:["أرباح التداول = دخل خاضع للضريبة (قانونياً)","لا يوجد نموذج محدد للإبلاغ عن أرباح العملات الرقمية","البنوك قد تطلب مستندات للتحويلات الكبيرة (>10,000$)","التخفيضات الكبيرة قد تثير شبهات غسيل أموال"]},{type:"heading",text:"غسيل الأموال والامتثال"},{type:"paragraph",text:"مصر عضو في مجموعة الـ FATF المالية. القانون المصري يلزم المنصات المالية بتطبيق إجراءات اعرف عميلك (KYC) والإبلاغ عن المعاملات المشبوهة. Eg-Money يطبق KYC عند التسجيل."},{type:"heading",text:"مخاطر قانونية محتملة"},{type:"list",items:["الحظر المستقبلي — الحكومة قد تحظر التداول في أي وقت","تجميد الحسابات البنكية — إذا اشتبه البنك في نشاطك","التحقيق الضريبي — إذا أبلغ البنك عن تحويلات كبيرة","فقدان الأموال — إذا أُغلقت المنصة بدون تنظيم"]},{type:"heading",text:"كيف تحمي نفسك قانونياً"},{type:"list",items:["سجّل كل صفقاتك وأرباحك (للإبلاغ الضريبي عند الطلب)","لا تحول مبالغ كبيرة دفعة واحدة — جزّئها","استخدم طرق دفع رسمية (بنوك، محافظ مرخصة)","لا تعلن عن أرباحك على وسائل التواصل","احتفظ بـ USDT في محافظ متعددة لتقليل المخاطر","استشر محامياً قبل التحويلات الكبيرة (>500,000 جنيه)"]},{type:"example",title:"سيناريو واقعي",body:"تاجر يحقق ربح 200,000 جنيه من USDT ويحولها لبنكه. البنك يطلب مصدر الأموال. التاجر يقدم سجلات التداول. البنك قد يطلب ضرائب (10-22.5%) على الأرباح قبل تحرير المبلغ. النتيجة: الربح الصافي بعد الضرائب ≈ 155,000-180,000 جنيه."},{type:"heading",text:"مستقبل التنظيم"},{type:"paragraph",text:"الحكومة المصرية تدرس تنظيم العملات الرقمية منذ 2023. من المتوقع إصدار قانون ينظم التداول والمنصات. حتى ذلك الحين، الوضع رمادي — تداول بحذر واحتفظ بسجلات."},{type:"tip",text:"القاعدة الذهبية: لا تستثمر أكثر مما تستطيع خسارته، واحتفظ بسجلات دقيقة، واستشر محامياً للتحويلات الكبيرة. الشفافية مع البنك أفضل من إخفاء الأموال."}],en:[{type:"paragraph",text:"The legal status of cryptocurrencies in Egypt is complex and not entirely clear. This article summarizes the current situation as of publication — consult a lawyer for specific advice."},{type:"warning",text:"This article is for general information only and is not legal advice. Laws change. Consult a specialist lawyer before making major financial decisions."},{type:"heading",text:"Central Bank of Egypt's position"},{type:"paragraph",text:"In 2018, the CBE issued a warning about cryptocurrencies but didn't explicitly ban them. In 2020, a banking law criminalized issuing or promoting cryptocurrencies without a license. However, personal trading between individuals isn't explicitly prohibited."},{type:"heading",text:"Financial Regulatory Authority position"},{type:"paragraph",text:"The FRA regulates licensed trading platforms. Most crypto platforms operating in Egypt are unlicensed. This puts users in a legal gray area."},{type:"heading",text:"Taxes on profits"},{type:"paragraph",text:"Legally, any trading profit is subject to income tax. But in practice, there's no clear mechanism for reporting crypto profits. If you convert large profits to EGP via bank, the bank may ask for the source of funds."},{type:"list",items:["Trading profits = taxable income (legally)","No specific form for reporting crypto profits","Banks may request documents for large transfers (>10,000$)","Large conversions may raise money laundering suspicions"]},{type:"heading",text:"AML and compliance"},{type:"paragraph",text:"Egypt is a FATF member. Egyptian law requires financial platforms to apply KYC (Know Your Customer) and report suspicious transactions. Eg-Money applies KYC at registration."},{type:"heading",text:"Potential legal risks"},{type:"list",items:["Future ban — government may ban trading at any time","Bank account freeze — if bank suspects your activity","Tax investigation — if bank reports large transfers","Loss of funds — if platform closes without regulation"]},{type:"heading",text:"How to protect yourself legally"},{type:"list",items:["Log all trades and profits (for tax reporting if requested)","Don't convert large amounts at once — split them","Use official payment methods (banks, licensed wallets)","Don't announce profits on social media","Keep USDT in multiple wallets to reduce risk","Consult a lawyer before large transfers (>500,000 EGP)"]},{type:"example",title:"Realistic scenario",body:"A trader makes 200,000 EGP profit from USDT and transfers to their bank. The bank asks for source of funds. The trader provides trading records. The bank may request taxes (10-22.5%) on profits before releasing the amount. Result: net profit after taxes ≈ 155,000-180,000 EGP."},{type:"heading",text:"Future regulation"},{type:"paragraph",text:"The Egyptian government has been studying crypto regulation since 2023. A law regulating trading and platforms is expected. Until then, the situation is gray — trade cautiously and keep records."},{type:"tip",text:"Golden rule: don't invest more than you can lose, keep accurate records, and consult a lawyer for large transfers. Transparency with your bank is better than hiding funds."}]}}];a.s(["EDU_ARTICLES",0,b,"GLOSSARY",0,[{term:{ar:"USDT",en:"USDT"},definition:{ar:"عملة رقمية مستقرة مربوطة بالدولار الأمريكي. 1 USDT ≈ 1 دولار.",en:"A stablecoin pegged to the US dollar. 1 USDT ≈ 1 USD."}},{term:{ar:"الـ Spread",en:"Spread"},definition:{ar:"الفرق بين سعر الشراء وسعر البيع. هذا كيف تربح المنصة.",en:"The difference between buy and sell prices. This is how the platform earns."}},{term:{ar:"الـ Escrow",en:"Escrow"},definition:{ar:"حساب ضمان مؤقت تحفظ فيه USDT حتى اكتمال الصفقة.",en:"A temporary holding account where USDT is locked until trade completion."}},{term:{ar:"P2P",en:"P2P"},definition:{ar:"تداول من شخص لشخص، بدون وسيط (المنصة توفر فقط الضمان).",en:"Peer-to-peer trading without intermediary (platform only provides escrow)."}},{term:{ar:"الـ DCA",en:"DCA"},definition:{ar:"استراتيجية شراء مبالغ ثابتة على فترات منتظمة لتقليل تأثير تقلبات السعر.",en:"Strategy of buying fixed amounts at regular intervals to reduce volatility impact."}},{term:{ar:"وقف الخسارة",en:"Stop-loss"},definition:{ar:"أمر بيع تلقائي عند سعر محدد لتقليل الخسارة.",en:"Automatic sell order at a specified price to limit loss."}},{term:{ar:"المراجحة",en:"Arbitrage"},definition:{ar:"شراء أصل بسعر منخفض في مكان وبيعه بسعر مرتفع في مكان آخر.",en:"Buying an asset at a low price in one place and selling at a higher price elsewhere."}},{term:{ar:"السيولة",en:"Liquidity"},definition:{ar:"مدى سهولة شراء/بيع أصل بدون التأثير على السعر.",en:"How easily an asset can be bought/sold without affecting the price."}},{term:{ar:"الـ KYC",en:"KYC"},definition:{ar:"اعرف عميلك — إجراءات التحقق من هوية المستخدم.",en:"Know Your Customer — user identity verification procedures."}},{term:{ar:"الـ FUD",en:"FUD"},definition:{ar:"الخوف، عدم اليقين، والشك — تكتيك لنشر الذعر للتأثير على الأسعار.",en:"Fear, Uncertainty, Doubt — tactic to spread panic affecting prices."}}]])}];

